import React, { Component } from "react";
import { Icon } from "antd";

class LandingTwo extends Component {
  render() {
    return (
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          flexDirection: "row",
          height: "45vh",
          paddingBottom: "5vh",
          backgroundColor: "#1890ff"
        }}
      >
        <div
          style={{
            display: "flex",
            flexDirection: "column"
          }}
        >
          <div>
            <div
              style={{
                fontWeight: "bold",
                fontSize: "4vw",
                color: "black"
              }}
            >
              Greetings.
            </div>
          </div>
        </div>
      </div>
    );
  }
}

export default LandingTwo;
